&quot;;}?&gt; 6.2 Golang操作 mainimport ( &quot;context&quot; &quot;encoding/json&quot; &quot;fmt&quot; &quot;log&quot; &quot;time&quot; &quot;github.com/elastic/go-elasticsearch/v8&quot; &quot;github.com/elastic/go-elasticsearch/v8/esapi&quot;)type BlogPost struct { Title string `json:&quot;title&quot;` Content string `json:&quot;content&quot;` Author string `json:&quot;author&quot;` CreatedAt time.Time `json:&quot;created_at&quot;`}func main() { // 创建ES客户端 cfg := elasticsearch.Config{ Addresses: []string{&quot;http://localhost:9200&quot;}, } es, err := elasticsearch.NewClient(cfg) if err != nil { log.Fatalf(&quot;创建客户端失败: %s&quot;, err) } // 检查集群健康状态 res, err := es.Cluster.Health() if err != nil { log.Fatalf(&quot;获取集群健康状态失败: %s&quot;, err) } defer res.Body.Close() var health map[string]interface{} if err := json.NewDecoder(res.Body).Decode(&amp;health); err != nil { log.Fatalf(&quot;解析响应失败: %s&quot;, err) } fmt.Printf(&quot;集群状态: %s
&quot;, health[&quot;status&quot;]) // 创建索引 createIndex(es) // 索引文档 indexDocument(es) // 搜索文档 searchDocuments(es) // 聚合查询 aggregateData(es)}func createIndex(es *elasticsearch.Client) { req := esapi.IndicesCreateRequest{ Index: &quot;blog_posts&quot;, Body: strings.NewReader(`{ &quot;settings&quot;: { &quot;number_of_shards&quot;: 3, &quot;number_of_replicas&quot;: 1 }, &quot;mappings&quot;: { &quot;properties&quot;: { &quot;title&quot;: { &quot;type&quot;: &quot;text&quot; }, &quot;content&quot;: { &quot;type&quot;: &quot;text&quot; }, &quot;author&quot;: { &quot;type&quot;: &quot;keyword&quot; }, &quot;created_at&quot;: { &quot;type&quot;: &quot;date&quot; } } } }`), } res, err := req.Do(context.Background(), es) if err != nil { log.Fatalf(&quot;创建索引失败: %s&quot;, err) } defer res.Body.Close() if res.IsError() { log.Fatalf(&quot;创建索引错误: %s&quot;, res.String()) } fmt.Println(&quot;索引创建成功&quot;)}func indexDocument(es *elasticsearch.Client) { post := BlogPost{ Title: &quot;Golang操作Elasticsearch&quot;, Content: &quot;这是一篇使用Golang操作Elasticsearch的示例文章&quot;, Author: &quot;王五&quot;, CreatedAt: time.Now(), } data, err := json.Marshal(post) if err != nil { log.Fatalf(&quot;序列化失败: %s&quot;, err) } req := esapi.IndexRequest{ Index: &quot;blog_posts&quot;, DocumentID: &quot;2&quot;, Body: strings.NewReader(string(data)), Refresh: &quot;true&quot;, } res, err := req.Do(context.Background(), es) if err != nil { log.Fatalf(&quot;索引文档失败: %s&quot;, err) } defer res.Body.Close() if res.IsError() { log.Fatalf(&quot;索引文档错误: %s&quot;, res.String()) } fmt.Println(&quot;文档索引成功&quot;)}func searchDocuments(es *elasticsearch.Client) { req := esapi.SearchRequest{ Index: []string{&quot;blog_posts&quot;}, Body: strings.NewReader(`{ &quot;query&quot;: { &quot;match&quot;: { &quot;title&quot;: &quot;Golang&quot; } }, &quot;sort&quot;: [ { &quot;created_at&quot;: &quot;desc&quot; } ] }`), Size: esapi.IntPtr(10), } res, err := req.Do(context.Background(), es) if err != nil { log.Fatalf(&quot;搜索失败: %s&quot;, err) } defer res.Body.Close() if res.IsError() { log.Fatalf(&quot;搜索错误: %s&quot;, res.String()) } var result map[string]interface{} if err := json.NewDecoder(res.Body).Decode(&amp;result); err != nil { log.Fatalf(&quot;解析搜索结果失败: %s&quot;, err) } hits := result[&quot;hits&quot;].(map[string]interface{})[&quot;hits&quot;].([]interface{}) fmt.Printf(&quot;搜索结果数量: %d
&quot;, len(hits)) for _, hit := range hits { source := hit.(map[string]interface{})[&quot;_source&quot;].(map[string]interface{}) fmt.Printf(&quot;标题: %s
&quot;, source[&quot;title&quot;]) }}func aggregateData(es *elasticsearch.Client) { req := esapi.SearchRequest{ Index: []string{&quot;blog_posts&quot;}, Body: strings.NewReader(`{ &quot;size&quot;: 0, &quot;aggs&quot;: { &quot;authors&quot;: { &quot;terms&quot;: { &quot;field&quot;: &quot;author.keyword&quot;, &quot;size&quot;: 10 } } } }`), } res, err := req.Do(context.Background(), es) if err != nil { log.Fatalf(&quot;聚合查询失败: %s&quot;, err) } defer res.Body.Close() var result map[string]interface{} if err := json.NewDecoder(res.Body).Decode(&amp;result); err != nil { log.Fatalf(&quot;解析聚合结果失败: %s&quot;, err) } aggs := result[&quot;aggregations&quot;].(map[string]interface{}) authors := aggs[&quot;authors&quot;].(map[string]interface{})[&quot;buckets&quot;].([]interface{}) fmt.Println(&quot;作者统计:&quot;) for _, bucket := range authors { b := bucket.(map[string]interface{}) fmt.Printf(&quot;%s: %d
&quot;, b[&quot;key&quot;], int(b[&quot;doc_count&quot;].(float64))) }} 6.3 Python操作 elasticsearch import Elasticsearchfrom datetime import datetimeimport json# 创建ES客户端es = Elasticsearch( hosts=[&quot;http://localhost:9200&quot;], basic_auth=(&quot;username&quot;, &quot;password&quot;), # 8.x版本需要认证 verify_certs=False # 生产环境不要禁用证书验证)# 检查连接if not es.ping(): raise ValueError(&quot;连接Elasticsearch失败&quot;)print(&quot;成功连接到Elasticsearch&quot;)# 创建索引index_name = &quot;blog_posts&quot;index_body = { &quot;settings&quot;: { &quot;number_of_shards&quot;: 3, &quot;number_of_replicas&quot;: 1 }, &quot;mappings&quot;: { &quot;properties&quot;: { &quot;title&quot;: {&quot;type&quot;: &quot;text&quot;}, &quot;content&quot;: {&quot;type&quot;: &quot;text&quot;}, &quot;author&quot;: {&quot;type&quot;: &quot;keyword&quot;}, &quot;created_at&quot;: {&quot;type&quot;: &quot;date&quot;} } }}# 如果索引存在则删除（测试用）if es.indices.exists(index=index_name): es.indices.delete(index=index_name)# 创建新索引response = es.indices.create(index=index_name, body=index_body)print(f&quot;索引创建结果: {response}&quot;)# 索引文档doc = { &quot;title&quot;: &quot;Python操作Elasticsearch&quot;, &quot;content&quot;: &quot;这是一篇使用Python操作Elasticsearch的示例文章&quot;, &quot;author&quot;: &quot;赵六&quot;, &quot;created_at&quot;: datetime.now().isoformat()}# 索引单个文档response = es.index(index=index_name, id=&quot;3&quot;, document=doc, refresh=True)print(f&quot;文档索引结果: {response}&quot;)# 批量索引文档docs = [ { &quot;title&quot;: &quot;Elasticsearch性能优化&quot;, &quot;content&quot;: &quot;如何优化Elasticsearch查询性能&quot;, &quot;author&quot;: &quot;张三&quot;, &quot;created_at&quot;: datetime.now().isoformat() }, { &quot;title&quot;: &quot;Docker与Elasticsearch&quot;, &quot;content&quot;: &quot;使用Docker部署Elasticsearch集群&quot;, &quot;author&quot;: &quot;李四&quot;, &quot;created_at&quot;: datetime.now().isoformat() }]for i, doc in enumerate(docs, 4): es.index(index=index_name, id=str(i), document=doc)# 搜索文档search_body = { &quot;query&quot;: { &quot;match&quot;: { &quot;title&quot;: &quot;Elasticsearch&quot; } }, &quot;sort&quot;: [ {&quot;created_at&quot;: &quot;desc&quot;} ], &quot;size&quot;: 10}response = es.search(index=index_name, body=search_body)print(f&quot;搜索结果数量: {response['hits']['total']['value']}&quot;)for hit in response['hits']['hits']: print(f&quot;ID: {hit['_id']}, 标题: {hit['_source']['title']}, 作者: {hit['_source']['author']}&quot;)# 聚合查询agg_body = { &quot;size&quot;: 0, &quot;aggs&quot;: { &quot;authors&quot;: { &quot;terms&quot;: { &quot;field&quot;: &quot;author.keyword&quot;, &quot;size&quot;: 10 } }, &quot;monthly_posts&quot;: { &quot;date_histogram&quot;: { &quot;field&quot;: &quot;created_at&quot;, &quot;calendar_interval&quot;: &quot;month&quot; } } }}response = es.search(index=index_name, body=agg_body)# 作者统计authors = response['aggregations']['authors']['buckets']print(&quot;
作者统计:&quot;)for author in authors: print(f&quot;{author['key']}: {author['doc_count']}篇文章&quot;)# 按月统计monthly = response['aggregations']['monthly_posts']['buckets']print(&quot;
按月统计:&quot;)for month in monthly: print(f&quot;{month['key_as_string']}: {month['doc_count']}篇文章&quot;)# 范围查询range_query = { &quot;query&quot;: { &quot;range&quot;: { &quot;created_at&quot;: { &quot;gte&quot;: &quot;2024-01-01T00:00:00&quot;, &quot;lte&quot;: &quot;2024-12-31T23:59:59&quot; } } }}response = es.search(index=index_name, body=range_query)print(f&quot;
2024年文章数量: {response['hits']['total']['value']}&quot;)# 更新文档update_body = { &quot;doc&quot;: { &quot;content&quot;: &quot;更新后的内容 - Elasticsearch是强大的搜索引擎&quot; }}response = es.update(index=index_name, id=&quot;3&quot;, body=update_body)print(f&quot;
文档更新结果: {response}&quot;)# 删除文档response = es.delete(index=index_name, id=&quot;3&quot;)print(f&quot;
文档删除结果: {response}&quot;) 7. 生产环境关键注意事项7.1 性能优化 硬件规划： CPU：至少4核，推荐8核以上 内存：64GB以上，JVM堆内存不超过31GB 磁盘：SSD硬盘，RAID 10配置 网络：万兆网络，低延迟 索引优化： 12345# 写入性能优化index.refresh_interval: 30sindex.number_of_replicas: 0 # 初始写入时设置为0，完成后增加副本index.translog.durability: asyncindex.translog.sync_interval: 30s 查询优化： 避免使用wildcard查询，改用ngram分词 限制size参数，避免返回过多数据 使用filter上下文代替query上下文，利用缓存 7.2 安全配置 必须启用的安全措施： 12345678910# elasticsearch.ymlxpack.security.enabled: truexpack.security.authc: anonymous: username: anonymous roles: [anonymous] realms: native: native1: order: 0 证书配置： 123# 生成证书bin/elasticsearch-certutil cabin/elasticsearch-certutil cert --ca elastic-stack-ca.p12 访问控制： 为不同应用创建专用用户 遵循最小权限原则 定期轮换密码和API密钥 安全警告：暴露在公网的Elasticsearch实例必须配置防火墙规则和身份认证，否则可能导致数据泄露或勒索攻击！ 7.3 备份与恢复 快照配置： 12# elasticsearch.ymlpath.repo: [&quot;/mnt/backups&quot;] 创建快照仓库： 1234567curl -XPUT 'http://localhost:9200/_snapshot/my_backup' -H 'Content-Type: application/json' -d '{ &quot;type&quot;: &quot;fs&quot;, &quot;settings&quot;: { &quot;location&quot;: &quot;/mnt/backups&quot;, &quot;compress&quot;: true }}' 创建快照： 1curl -XPUT 'http://localhost:9200/_snapshot/my_backup/snapshot_2024_01_15?wait_for_completion=true' 备份策略：建议每日增量备份，每周全量备份，备份数据存储在不同地理位置，确保灾难恢复能力。 7.4 监控与告警 监控指标： 集群健康状态 JVM内存使用率 索引和查询延迟 磁盘空间使用率 线程池队列大小 推荐监控工具： Elastic Stack（ELK）自带监控 Prometheus + Grafana Datadog、New Relic等APM工具 告警规则： 12345# 示例告警条件- 当集群状态为red时立即告警- 当JVM内存使用率&gt;80%时告警- 当磁盘空间&lt;15%时告警- 当查询延迟&gt;1s时告警 监控提醒：不要等到问题发生才处理，建立主动监控体系，设置合理的阈值和告警渠道。 8.Elasticsearch 关键版本特性演变分析Elasticsearch 作为分布式搜索和分析引擎，经历了多次重大版本迭代，每个版本都带来了显著的特性和架构变化。以下是值得关注的关键版本特性演变： 5.x 版本（2016-2017）：性能与基础架构革新5.x 版本基于 Lucene 6.x，带来了 25% 的查询性能提升，并将默认打分机制从 TF-IDF 改为更先进的 BM25 算法。 该版本摒弃了传统的 string 字段类型，转而使用 text 和 keyword 两种类型来分别处理全文搜索和精确匹配场景，这一变化对数据建模产生了深远影响。 5.x 版本仍然支持一个索引包含多个文档类型（type），为后续版本的类型限制埋下了伏笔。 6.x 版本（2017-2019）：向单类型索引过渡Elasticsearch 6.0.0 基于 Lucene 7.0.1 发布，支持无宕机滚动升级，允许跨 5.x 和 6.x 集群进行搜索，且无需重新索引旧数据。 6.x 版本引入了重大架构变化：一个索引只能包含一个文档类型，这是向完全移除类型概念过渡的关键步骤。 该版本还引入了稀疏性 Doc Values 优化，显著减少了磁盘空间使用量，同时保持了查询性能。 7.x 版本（2019-2021）：类型移除与性能优化Elasticsearch 7.0 带来了突破性变化：完全移除了文档类型（type）概念，简化了数据模型。 7.x 版本引入了新的查询引擎和优化器，能够更好地处理复杂查询请求，提供更快的搜索响应，特别是在大规模数据集上表现突出。 ES 7.7 版本在机器学习领域取得重大进展，将分类能力从仅支持两个类别扩展到 30 多个类别，并增强了内存控制机制，有效防止了 OOM（内存溢出）问题。 7.x 版本的兼容性限制：只能读取 6.0 或更高版本创建的索引，如果存在 6.0 之前版本创建的索引，Elasticsearch 7.0 节点将无法启动。 8.x 版本（2022-至今）：安全简化与智能化Elasticsearch 8.x 版本最显著的变化是默认开启三层安全配置，并极大简化了安全设置流程。在 7.x 版本中开启安全需要 10 个复杂步骤（如 CA 证书配置、YML 文件修改等），而 8.x 版本只需简单几步即可完成。 8.x 版本通过 Lucene 9.0 引擎升级，实现了 14.78%-41.2% 的存储成本降低，大幅提升了存储效率。 2024 年 8 月，Elasticsearch 8.16.0 版本重新引入了 GNU Affero General Public License (AGPL) 作为可选许可，使 Elasticsearch 重新成为自由开源软件，这一决定对社区和商业用户都产生了重大影响。 版本升级注意事项从 5.x 到 8.x 的演进过程中，Elasticsearch 始终保持谨慎的向后兼容策略。例如，7.x 版本支持从 6.0 或更高版本创建的索引，但需要移除或重新索引 5.x 或更早版本创建的索引。 重大版本升级可能包含功能变更，这些变更是由于主要 Elasticsearch 版本之间的功能差异导致的，需要用户执行额外的步骤来确保平滑过渡。 9. 小结Elasticsearch作为现代搜索和分析引擎，其强大的功能和灵活的架构使其成为处理海量数据的理想选择。从本文中，我们系统地学习了： 版本演进：了解了Elasticsearch从1.x到8.x的重大变化，为版本选择提供依据 架构设计：掌握了从单节点到集群的部署模式，理解了节点角色分配的重要性 容器化部署：学会了使用Docker快速部署Elasticsearch，适应现代DevOps流程 多语言集成：通过PHP、Golang、Python的实际代码，展示了如何与应用系统集成 生产实践：强调了性能优化、安全配置、备份恢复等关键注意事项 最终建议： 循序渐进：从单节点开始学习，逐步过渡到集群 安全第一：生产环境必须启用完整安全配置 监控先行：部署监控系统，早发现问题早处理 持续学习：Elasticsearch生态快速发展，保持学习更新 Elasticsearch 的版本演进体现了其从单一搜索引擎向全能数据平台的转变：5.x 专注于性能提升，6.x 优化数据模型，7.x 增强查询能力和机器学习，8.x 简化安全配置并提升存储效率。了解这些版本特性演变对于架构设计、版本选型和升级规划至关重要，能够帮助用户在不同场景下选择最适合的 Elasticsearch 版本。 重要提醒：本文成文截至时间2024年3月，后续版本更新变化以官网为准⚠️

Redis 概述Redis 作为当今最流行的内存数据结构存储系统，凭借其卓越的性能和丰富的数据类型，已成为现代应用架构中不可或缺的组件。本文将基于 Debian 12 环境从 Redis 的版本演进出发，完整部署流程，从单体到集群，从基础配置到高级应用，最后提供多语言客户端操作示例，帮助新手全面快速掌握 Redis 技术栈的基本使用，有个相对基础的思路。 一、Redis 版本历史与特性演进1.1 开源协议的重大变化2024 年 3 月 20 日，Redis Labs 宣布从 Redis 7.4 开始，将原先宽松的 BSD 三条款许可修改为 Redis Source Available License（RSALv2）和 Server Side Public License（SSPLv1）双重许可协议。 这一变化意味着 Redis 7.4 及以上版本不再符合 OSI（开放源代码促进会）定义的开源标准，对商业使用场景产生了深远影响。 1.2 主要版本特性概览Redis 7.0 - 历史性变革 统一发布策略：Redis 7.0 引入了 Unified Redis Release 统一发布策略，这是 Redis 历史上改变最多的大版本。 50+ 新命令：包含大量核心新特性和改进，显著提升性能、功能和可靠性。 AOF 存储优化：将 AOF 文件的存储方式改为在一个文件夹下存储多个文件，提升写入性能。 RDB 版本升级：将持久化文件 RDB 的版本升级为 10，与之前的 RDB 文件版本不兼容。 Redis 7.2 - 客户端缓存增强 Client-Side Caching：客户端缓存功能大幅降低网络延迟，提升读取性能。 地理空间查询改进：优化地理空间数据操作，支持更复杂的地理位置计算。 JSON 数据操作简化：提供更简洁的 JSON 数据处理接口。 Redis 7.4 - 企业级特性 哈希字段过期：支持对哈希表中的单个字段设置过期时间。 指标流引擎预览：提供实时监控和分析能力。 集群管理 API 增强：新增用于检查数据库可用性、重新平衡分片、故障转移分片和控制数据库流量的 API。 二、Redis 基本部署 系统测试环境：Debian 12 Redis当前稳定版本：Redis 7.4 2.1 系统环境准备12345# 更新系统包列表sudo apt update -y# 安装基础依赖sudo apt install -y build-essential libssl-dev libsystemd-dev 2.2 安装 Redis方法一：APT 官方仓库安装（推荐）12345# 安装 Redis 服务器sudo apt install -y redis-server# 检查安装状态sudo systemctl status redis-server Redis 安装完成后，默认已启动并设置为开机自启。 方法二：源码编译安装（定制需求）1234567891011121314# 安装编译依赖sudo apt install -y wget tar make gcc# 下载 Redis 源码wget https://download.redis.io/redis-stable.tar.gztar -xzvf redis-stable.tar.gzcd redis-stable# 编译安装makesudo make install# 验证安装redis-server --version 在 Debian 12 (Bookworm) 上构建并运行 Redis 开源版需要先安装所需依赖项，然后下载并提取 Redis 源代码进行构建。 三、Redis 核心原理与特性3.1 核心架构原理Redis 采用单线程事件驱动模型，通过 I/O 多路复用技术实现高并发处理。其核心架构包含： 事件循环：处理客户端连接、命令执行、定时任务 内存管理：高效的内存分配器和对象共享机制 持久化机制：RDB 快照和 AOF 日志两种持久化方式 复制机制：主从复制保证数据高可用 3.2 数据类型与应用场景 数据类型 特点 典型应用场景 String 简单键值对，支持 INCR/DECR 计数器、缓存、分布式锁 Hash 字段-值映射表 对象存储、用户信息 List 双向链表 消息队列、最新消息列表 Set 无序集合，元素唯一 标签系统、好友关系 Sorted Set 有序集合，按分数排序 排行榜、优先级队列 Bitmap 位图操作 用户签到、活跃度分析 HyperLogLog 基数统计 UV 统计、数据去重 四、redis.conf 详细配置解析123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123# Redis 配置文件详细中文注释# 适用于 Redis 7.x 版本# ======================== 基本配置 ========================# 绑定 IP 地址，注释掉或设置为 0.0.0.0 允许远程访问# 默认只允许本地访问，生产环境需要根据安全策略配置bind 127.0.0.1 ::1# 保护模式，当没有设置密码且只绑定 127.0.0.1 时启用protected-mode yes# 服务端口号port 6379# TCP 连接 backlog 队列大小tcp-backlog 511# 超时时间，0 表示永不超时（单位：秒）timeout 0# TCP keepalive 时间（单位：秒）tcp-keepalive 300# ======================== 守护进程配置 ========================# 是否以守护进程方式运行daemonize no# PID 文件路径pidfile /var/run/redis/redis-server.pid# 日志级别：debug, verbose, notice, warningloglevel notice# 日志文件路径logfile /var/log/redis/redis-server.log# ======================== 内存管理 ========================# 最大内存限制，0 表示无限制（单位：bytes）maxmemory 0# 内存淘汰策略，当达到 maxmemory 时触发# noeviction: 不淘汰，返回错误# allkeys-lru: 所有 key 的 LRU 淘汰# volatile-lru: 仅对设置了过期时间的 key 进行 LRU 淘汰# allkeys-random: 所有 key 的随机淘汰# volatile-random: 仅对设置了过期时间的 key 进行随机淘汰# volatile-ttl: 优先淘汰剩余时间短的 keymaxmemory-policy noeviction# ======================== 持久化配置 ========================# RDB 持久化配置# 格式：save &lt;秒数&gt; &lt;变化次数&gt;# 900 秒内有 1 次变化则保存# 300 秒内有 10 次变化则保存# 60 秒内有 10000 次变化则保存save 900 1save 300 10save 60 10000# RDB 文件名dbfilename dump.rdb# RDB 文件保存目录dir /var/lib/redis# AOF 持久化配置# 是否启用 AOFappendonly no# AOF 文件名appendfilename &quot;appendonly.aof&quot;# AOF 同步策略# always: 每次写操作都同步（最安全，性能最差）# everysec: 每秒同步一次（推荐，平衡安全性和性能）# no: 由操作系统决定（性能最好，安全性最差）appendfsync everysec# ======================== 安全配置 ========================# 访问密码，建议设置强密码requirepass your_strong_password_here# 命令重命名，用于禁用危险命令# rename-command FLUSHDB &quot;&quot;# rename-command FLUSHALL &quot;&quot;# ======================== 集群配置 ========================# 是否启用集群模式cluster-enabled no# 集群节点超时时间（毫秒）cluster-node-timeout 15000# 集群配置文件cluster-config-file nodes-6379.conf# ======================== 客户端配置 ========================# 最大客户端连接数maxclients 10000# 客户端输出缓冲区限制# 格式：client-output-buffer-limit &lt;类别&gt; &lt;硬限制&gt; &lt;软限制&gt; &lt;软限制时间&gt;client-output-buffer-limit normal 0 0 0client-output-buffer-limit replica 256mb 64mb 60client-output-buffer-limit pubsub 32mb 8mb 60# ======================== 性能调优 ========================# 哈希表小对象优化hash-max-ziplist-entries 512hash-max-ziplist-value 64# 列表小对象优化list-max-ziplist-size -2# 集合小对象优化set-max-intset-entries 512# 有序集合小对象优化zset-max-ziplist-entries 128zset-max-ziplist-value 64# 活跃碎片整理activedefrag yes 找到 bind 127.0.0.1 ::1 配置项，将其注释掉或修改为允许的 IP 地址，然后保存并重启 Redis 服务。 五、从单体到集群：Redis 高可用架构5.1 单体架构部署单体架构适用于小型应用或开发环境，配置简单，维护成本低。 123456# 单体 Redis 配置要点bind 0.0.0.0 # 允许远程访问protected-mode no # 关闭保护模式requirepass your_password # 设置强密码maxmemory 2gb # 设置内存限制maxmemory-policy allkeys-lru # LRU 淘汰策略 5.2 主从复制架构12345678910# 主节点配置（master.conf）port 6379requirepass master_passwordmasterauth slave_password # 用于从节点验证# 从节点配置（slave.conf）port 6380slaveof 192.168.1.100 6379 # 主节点地址masterauth master_password # 主节点密码requirepass slave_password # 从节点密码 5.3 Redis Cluster 集群部署Redis 集群需要至少 6 个节点（3 主 3 从）才能保证高可用性。 部署步骤： 准备节点： 12# 创建集群目录mkdir -p /data/redis-cluster/{7000,7001,7002,7003,7004,7005} 配置文件模板（cluster-node.conf）： 123456789port 7000bind 0.0.0.0protected-mode nocluster-enabled yescluster-config-file nodes-7000.confcluster-node-timeout 15000appendonly yesrequirepass cluster_passwordmasterauth cluster_password 启动所有节点： 1234567# 为每个节点复制配置文件并修改端口号for port in {7000..7005}; do cp cluster-node.conf /data/redis-cluster/$port/redis.conf sed -i &quot;s/port 7000/port $port/&quot; /data/redis-cluster/$port/redis.conf sed -i &quot;s/nodes-7000.conf/nodes-$port.conf/&quot; /data/redis-cluster/$port/redis.conf redis-server /data/redis-cluster/$port/redis.confdone 创建集群： 12345redis-cli --cluster create \192.168.1.100:7000 192.168.1.100:7001 192.168.1.100:7002 \192.168.1.100:7003 192.168.1.100:7004 192.168.1.100:7005 \--cluster-replicas 1 \-a cluster_password 在每台服务器上分别创建三个不同的配置文件，例如：Redis 实例 1 监听端口 7000，作为集群的一个主节点；Redis 实例 2 监听端口 7001，作为集群的从节点。 六、Docker 容器化部署6.1 单机 Redis Docker 部署123456789101112131415161718192021# docker-compose.ymlversion: '3.8'services: redis: image: redis:7.2-alpine container_name: redis-single ports: - &quot;6379:6379&quot; volumes: - ./redis.conf:/usr/local/etc/redis/redis.conf - ./data:/data command: redis-server /usr/local/etc/redis/redis.conf restart: unless-stopped environment: - REDIS_PASSWORD=your_strong_password healthcheck: test: [&quot;CMD&quot;, &quot;redis-cli&quot;, &quot;ping&quot;] interval: 30s timeout: 10s retries: 3 6.2 Redis Cluster Docker 部署12345678910111213141516171819202122232425262728293031# docker-compose-cluster.ymlversion: '3.8'services: redis-node-1: image: redis:7.2-alpine container_name: redis-cluster-1 ports: - &quot;7000:7000&quot; - &quot;17000:17000&quot; volumes: - ./cluster/7000/redis.conf:/usr/local/etc/redis/redis.conf command: redis-server /usr/local/etc/redis/redis.conf restart: unless-stopped redis-node-2: image: redis:7.2-alpine container_name: redis-cluster-2 ports: - &quot;7001:7001&quot; - &quot;17001:17001&quot; volumes: - ./cluster/7001/redis.conf:/usr/local/etc/redis/redis.conf command: redis-server /usr/local/etc/redis/redis.conf restart: unless-stopped # ... 配置其他 4 个节点networks: redis-net: driver: bridge 通过自定义配置文件，我们可以确保 Redis 实例按照我们的业务需求和安全标准运行。 6.3 Docker 部署注意事项 数据持久化：必须挂载数据卷，避免容器重启数据丢失 网络配置：集群模式需要暴露集群总线端口（客户端端口 + 10000） 资源限制：设置合理的内存和 CPU 限制 健康检查：配置健康检查确保服务可用性 安全加固：设置密码、限制访问 IP、禁用危险命令 七、多语言客户端操作示例7.1 PHP 操作 Redis123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263&lt;?php// 安装：composer require predis/predisrequire 'vendor/autoload.php';use Predis\Client;// 连接配置$parameters = [ 'scheme' =&gt; 'tcp', 'host' =&gt; '127.0.0.1', 'port' =&gt; 6379, 'password' =&gt; 'your_password', 'database' =&gt; 0,];// 创建客户端$client = new Client($parameters);// 字符串操作$client-&gt;set('user:1:name', '张三');$client-&gt;setex('user:1:token', 3600, 'abc123'); // 设置过期时间$name = $client-&gt;get('user:1:name');echo &quot;用户名: &quot; . $name . &quot;
&quot;;// 哈希表操作$client-&gt;hset('user:1', 'name', '张三');$client-&gt;hset('user:1', 'email', 'zhangsan@example.com');$client-&gt;hset('user:1', 'age', 25);$userInfo = $client-&gt;hgetall('user:1');print_r($userInfo);// 列表操作$client-&gt;rpush('news:latest', '新闻1');$client-&gt;rpush('news:latest', '新闻2');$client-&gt;rpush('news:latest', '新闻3');$latestNews = $client-&gt;lrange('news:latest', 0, 2);print_r($latestNews);// 有序集合操作$client-&gt;zadd('leaderboard', 100, 'player1');$client-&gt;zadd('leaderboard', 150, 'player2');$client-&gt;zadd('leaderboard', 80, 'player3');$topPlayers = $client-&gt;zrevrange('leaderboard', 0, 2, ['withscores' =&gt; true]);print_r($topPlayers);// 事务操作$client-&gt;multi() -&gt;set('counter', 0) -&gt;incr('counter') -&gt;incr('counter') -&gt;exec();$counter = $client-&gt;get('counter');echo &quot;计数器值: &quot; . $counter . &quot;
&quot;;// 关闭连接$client-&gt;disconnect();?&gt; Redis 的操作很多，PHP 处理 Redis 的例子包括常用的一些方法，如字符串、哈希、列表、集合等数据类型的操作。 7.2 Golang 操作 Redis123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123package mainimport ( &quot;context&quot; &quot;fmt&quot; &quot;time&quot; &quot;github.com/redis/go-redis/v9&quot;)func main() { ctx := context.Background() // 创建 Redis 客户端 rdb := redis.NewClient(&amp;redis.Options{ Addr: &quot;localhost:6379&quot;, Password: &quot;your_password&quot;, DB: 0, }) // 测试连接 pong, err := rdb.Ping(ctx).Result() if err != nil { panic(err) } fmt.Println(&quot;连接成功:&quot;, pong) // 字符串操作 err = rdb.Set(ctx, &quot;user:2:name&quot;, &quot;李四&quot;, 0).Err() if err != nil { panic(err) } name, err := rdb.Get(ctx, &quot;user:2:name&quot;).Result() if err != nil { panic(err) } fmt.Println(&quot;用户名:&quot;, name) // 哈希表操作 userData := map[string]interface{}{ &quot;name&quot;: &quot;李四&quot;, &quot;email&quot;: &quot;lisi@example.com&quot;, &quot;age&quot;: 28, } err = rdb.HMSet(ctx, &quot;user:2&quot;, userData).Err() if err != nil { panic(err) } email, err := rdb.HGet(ctx, &quot;user:2&quot;, &quot;email&quot;).Result() if err != nil { panic(err) } fmt.Println(&quot;邮箱:&quot;, email) // 列表操作 err = rdb.RPush(ctx, &quot;products:hot&quot;, &quot;手机&quot;, &quot;电脑&quot;, &quot;平板&quot;).Err() if err != nil { panic(err) } products, err := rdb.LRange(ctx, &quot;products:hot&quot;, 0, -1).Result() if err != nil { panic(err) } fmt.Println(&quot;热门产品:&quot;, products) // 事务操作 tx := rdb.TxPipelined(ctx, func(pipe redis.Pipeliner) error { pipe.Set(ctx, &quot;order:count&quot;, 0, 0) pipe.Incr(ctx, &quot;order:count&quot;) pipe.Incr(ctx, &quot;order:count&quot;) return nil }) if err := tx[0].Err(); err != nil { panic(err) } orderCount, err := rdb.Get(ctx, &quot;order:count&quot;).Int64() if err != nil { panic(err) } fmt.Println(&quot;订单数量:&quot;, orderCount) // Pipeline 批量操作 pipe := rdb.Pipeline() pipe.Set(ctx, &quot;counter:view&quot;, 0, 0) pipe.Incr(ctx, &quot;counter:view&quot;) pipe.Incr(ctx, &quot;counter:view&quot;) pipe.Exec(ctx) viewCount, err := rdb.Get(ctx, &quot;counter:view&quot;).Int64() if err != nil { panic(err) } fmt.Println(&quot;浏览次数:&quot;, viewCount) // 发布订阅 pubsub := rdb.Subscribe(ctx, &quot;news_channel&quot;) defer pubsub.Close() // 启动 goroutine 处理消息 ch := pubsub.Channel() go func() { for msg := range ch { fmt.Printf(&quot;收到消息: %s
&quot;, msg.Payload) } }() // 发布消息 err = rdb.Publish(ctx, &quot;news_channel&quot;, &quot;Redis 发布订阅示例&quot;).Err() if err != nil { panic(err) } time.Sleep(2 * time.Second) // 等待消息处理 // 关闭连接 rdb.Close()} 通过 redis.NewClient 函数即可创建一个 redis 客户端，这个方法接收一个 redis.Options 对象参数，通过这个参数可以配置 redis 相关的属性。 7.3 Python 操作  redisfrom redis.cluster import RedisClusterimport timefrom datetime import datetime# 单机 Redis 连接def connect_redis(): return redis.Redis( host='localhost', port=6379, password='your_password', decode_responses=True, # 自动解码响应 db=0 )# 集群 Redis 连接def connect_redis_cluster(): return RedisCluster( host='localhost', port=7000, password='cluster_password', decode_responses=True )def string_operations(r): &quot;&quot;&quot;字符串操作示例&quot;&quot;&quot; print(&quot;=== 字符串操作 ===&quot;) # 设置键值 r.set('user:3:name', '王五') r.setex('user:3:session', 3600, 'session_token_123') # 设置过期时间 # 获取值 name = r.get('user:3:name') print(f&quot;用户名: {name}&quot;) # 批量操作 r.mset({ 'user:3:age': 30, 'user:3:city': '北京' }) # 递增操作 r.set('counter:views', 0) r.incr('counter:views') r.incr('counter:views', 5) views = r.get('counter:views') print(f&quot;浏览次数: {views}&quot;)def hash_operations(r): &quot;&quot;&quot;哈希表操作示例&quot;&quot;&quot; print(&quot;
