=== 列表操作 ===&quot;) # 添加元素 news_key = 'news:latest' r.rpush(news_key, '科技新闻1') r.rpush(news_key, '科技新闻2') r.rpush(news_key, '科技新闻3') # 获取范围 latest_news = r.lrange(news_key, 0, 2) print(f&quot;最新新闻: {latest_news}&quot;) # 弹出元素 last_news = r.rpop(news_key) print(f&quot;弹出的新闻: {last_news}&quot;) # 列表长度 news_count = r.llen(news_key) print(f&quot;剩余新闻数量: {news_count}&quot;)def sorted_set_operations(r): &quot;&quot;&quot;有序集合操作示例&quot;&quot;&quot; print(&quot;
=== 有序集合操作 ===&quot;) leaderboard_key = 'game:leaderboard' # 添加成员 r.zadd(leaderboard_key, {'player1': 100, 'player2': 150, 'player3': 80}) # 获取排名 rank = r.zrank(leaderboard_key, 'player2') print(f&quot;player2 排名: {rank}&quot;) # 获取分数 score = r.zscore(leaderboard_key, 'player2') print(f&quot;player2 分数: {score}&quot;) # 获取前3名 top_players = r.zrevrange(leaderboard_key, 0, 2, withscores=True) print(&quot;排行榜前3名:&quot;) for player, score in top_players: print(f&quot; {player}: {score}&quot;)def transaction_operations(r): &quot;&quot;&quot;事务操作示例&quot;&quot;&quot; print(&quot;
=== 事务操作 ===&quot;) # 创建管道 pipe = r.pipeline() try: # 开启事务 pipe.multi() # 事务中的操作 pipe.set('order:id', 1000) pipe.incr('order:id') pipe.incr('order:id') # 执行事务 results = pipe.execute() print(f&quot;事务执行结果: {results}&quot;) # 获取最终值 final_id = r.get('order:id') print(f&quot;最终订单ID: {final_id}&quot;) except redis.WatchError: print(&quot;事务执行失败，数据被修改&quot;) finally: pipe.reset()def pubsub_operations(r): &quot;&quot;&quot;发布订阅操作示例&quot;&quot;&quot; print(&quot;
=== 发布订阅操作 ===&quot;) # 创建发布/订阅客户端 pubsub = r.pubsub() # 订阅频道 pubsub.subscribe('news_channel') print(&quot;已订阅 news_channel 频道&quot;) # 发布消息 r.publish('news_channel', 'Python Redis 发布订阅示例') print(&quot;已发布消息到 news_channel&quot;) # 等待接收消息 message = pubsub.get_message(timeout=2) if message: print(f&quot;收到消息: {message}&quot;) # 退订 pubsub.unsubscribe('news_channel')def main(): print(f&quot;开始测试 Redis 操作: {datetime.now()}&quot;) # 连接 Redis r = connect_redis() try: # 测试连接 ping_result = r.ping() print(f&quot;Redis 连接状态: {ping_result}&quot;) # 执行各种操作 string_operations(r) hash_operations(r) list_operations(r) sorted_set_operations(r) transaction_operations(r) pubsub_operations(r) print(f&quot;
测试完成: {datetime.now()}&quot;) except Exception as e: print(f&quot;发生错误: {e}&quot;) finally: r.close()if __name__ == &quot;__main__&quot;: main() 连接示例中，可以通过 decode_responses=True 参数来解码 Redis 返回的二进制响应。 八、关键注意事项与最佳实践8.1 安全防护 密码策略：必须设置强密码，避免使用默认或弱密码 网络隔离：Redis 服务不应直接暴露在公网，应通过防火墙或安全组限制访问 命令禁用：通过 rename-command 禁用危险命令如 FLUSHDB、FLUSHALL、CONFIG 定期审计：监控 Redis 日志，检查异常访问和操作 8.2 性能优化 内存管理： 合理设置 maxmemory 和淘汰策略 避免大 key 操作，单个 value 不超过 10MB 使用合适的数据结构，如用 Hash 存储对象 连接管理： 使用连接池，避免频繁创建连接 设置合理的超时时间，及时释放空闲连接 监控连接数，防止连接泄漏 持久化策略： 根据业务需求选择 RDB、AOF 或混合持久化 避免在高峰时段执行 BGSAVE 定期备份持久化文件 8.3 高可用保障 集群部署：生产环境必须使用集群模式，至少 3 主 3 从 监控告警：监控关键指标：内存使用率、连接数、命中率、延迟 故障转移：配置自动故障转移，测试故障恢复流程 数据备份：定期备份数据，验证备份文件可用性 8.4 版本选择建议 开源版本限制：Redis 7.4 及以上版本采用新的许可协议，商业使用需谨慎评估 稳定版本推荐：生产环境建议使用 Redis 7.0 或 7.2 稳定版本 兼容性考虑：升级前测试客户端兼容性，特别是新协议支持 长期支持：选择有长期支持的版本，避免频繁升级 九、感悟Redis 作为高性能的内存数据库，在现代应用架构中扮演着越来越重要的角色。从版本演进来看，Redis 7.x 系列带来了众多创新特性，但也伴随着许可协议的重大变化，需要开发者和企业重新评估技术选型策略。 在 Debian 12 环境下部署 Redis，无论是单体、主从还是集群模式，都需要深入理解其配置参数和工作原理。通过合理的配置优化，可以充分发挥 Redis 的性能优势，同时保障系统的安全性和稳定性。 Docker 容器化部署为 Redis 提供了更灵活的部署方式，特别是在微服务架构中，可以快速构建和扩展 Redis 服务。多语言客户端的支持使得 Redis 能够无缝集成到各种技术栈中，为应用提供强大的缓存、队列和实时数据处理能力。 随着云原生和分布式系统的发展，Redis 的应用场景将更加广泛。掌握 Redis 的核心原理、最佳实践和运维技巧，将成为开发者和架构师的必备技能。在选择 Redis 作为技术方案时，需要综合考虑性能需求、成本预算、合规要求等因素，做出最适合业务发展的技术决策。 重要提醒 ⚠️ ：由于 Redis 7.4 及以上版本的许可协议变更，建议在商业项目中谨慎评估使用风险，必要时考虑开源替代方案如 Valkey、DragonflyDB 等。 十、Redis、Valkey、DragonflyDB 三者深度对比与技术选型指南（个人观点，自行评估⚠️）Redis：内存数据库的开创者Redis自2009年诞生以来，一直是内存数据库领域的标杆。然而在2024-2025年，Redis经历了两次重大许可变更，从宽松的BSD协议转向带有商业限制的SSPLv1和RSALv2协议，引发了社区的广泛争议。 2025年5月，Redis 8.0发布，重新开源，采用AGPLv3许可证作为三种许可证选项之一，试图修复与社区的关系。 Valkey：社区驱动的Redis分支面对Redis的许可变更，社区在2024年创建了Valkey分支，目标是保持Redis的核心特性和API兼容性，同时回归真正的开源理念。到2025年，Arch Linux等主流发行版已宣布采用Valkey取代Redis。 Valkey完全继承了Redis 7.0的技术基础，但保持了BSD许可证，为开发者提供了无商业限制的选择。 DragonflyDB：新一代内存数据库2022年，一位前谷歌、前亚马逊的工程师推出了DragonflyDB，用C/C++编写，基于BSL许可分发。 DragonflyDB采用了全新的架构设计，声称在性能上比Redis快25倍，单实例可支持数百万QPS，成为内存数据库领域的新锐力量。 核心架构对比线程模型 Redis/Valkey：采用单线程事件驱动模型，通过I/O多路复用技术实现高并发，但无法充分利用多核CPU资源。 DragonflyDB：采用多线程、无共享（Shared-nothing）架构，能够充分利用现代多核CPU的计算能力，实现真正的水平扩展。 数据结构与算法 Redis/Valkey：使用传统的数据结构，如跳跃表、字典等，在单线程环境下优化良好。 DragonflyDB：创新性地实现了名为”dashtable”的哈希表结构，以最小化内存开销和延迟，这是其性能优势的关键所在。 ####集群与扩展性 Redis：需要通过Redis Cluster实现分布式，配置相对复杂。 Valkey：继承Redis的集群方案，保持兼容性。 DragonflyDB：自带集群能力，可以利用多核，接口层面完全兼容Redis，简化了架构复杂度。 性能对比分析基准测试结果根据官方基准测试数据，DragonflyDB在典型工作负载下实现了25倍于Redis的性能提升，单个Dragonfly服务器每秒可以处理数百万个请求。 在5GB存储测试中，Dragonfly所需的内存也显著低于Redis，展现出更高的内存效率。 实际应用场景表现 高并发读写场景：DragonflyDB在需要超高QPS的场景（如秒杀、实时推荐）中表现卓越，单实例支持百万量级QPS。 内存密集型应用：DragonflyDB在应对TB级别的内存数据集时，内存效率优势明显。 传统业务场景：Redis/Valkey在常规缓存、会话管理等场景中仍然表现出色，且生态系统更加成熟。 许可协议对比Redis 许可证演变 历史：从BSD 3-Clause到双重许可证（RSALv2/SSPLv1），再到Redis 8.0的三许可证模式（RSALv2/SSPLv1/AGPLv3）。 现状：虽然恢复了AGPLv3使其重新获得开源分类，但复杂的许可结构给企业带来合规风险。 ####Valkey 许可证 协议类型：BSD许可证，完全开源，无商业限制。 优势：符合开源理念，企业可以自由使用、修改和分发，无许可合规风险。 ####DragonflyDB 许可证 协议类型：BSL（Business Source License），一种”源码可用”但非严格开源的协议。 限制：在特定条件下（如商业用途、大规模部署）可能需要购买商业许可。 优势：在开发阶段和小规模部署时免费，降低了入门门槛。 生态系统与兼容性API 兼容性 Valkey：100%兼容Redis协议，现有Redis客户端和工具无需修改即可使用。 DragonflyDB：接口层面完全兼容Redis，支持大部分Redis命令，但在某些高级特性（如模块、特定数据结构）上可能存在差异。 工具链支持 Redis：拥有最完善的生态系统，包括监控工具（RedisInsight）、管理工具、客户端库等。 Valkey：继承Redis的工具链，大部分Redis工具可以直接使用。 DragonflyDB：生态系统相对较新，工具链仍在完善中，但发展迅速。 ####云服务支持 Redis：所有主流云服务商都提供托管Redis服务（如AWS ElastiCache、Azure Cache for Redis）。 Valkey：云服务商正在逐步增加支持，但覆盖范围有限。 DragonflyDB：部分云服务商开始提供托管服务，但普及度较低。 技术选型建议选择 Redis 的场景 已有Redis投资：已经深度使用Redis，有成熟的运维体系和开发习惯。 企业级支持需求：需要官方商业支持和SLA保障。 复杂特性需求：需要Redis Modules（如RediSearch、RedisJSON）等高级特性。 混合许可接受度：能够接受Redis 8.0的三重许可模式，且有法务团队进行合规审查。 选择 Valkey 的场景 开源合规优先：企业有严格的开源合规要求，无法接受SSPL/RSAL等限制性协议。 平滑迁移需求：希望从Redis无缝迁移，避免代码重构和架构调整。 社区驱动偏好：信任社区驱动的开源项目，而非单一商业公司的控制。 稳定性要求高：需要经过充分验证的稳定版本，而非实验性新技术。 选择 DragonflyDB 的场景 极致性能需求：应用场景需要超高QPS（&gt;100K）或低延迟（&lt;1ms）。 成本敏感型应用：通过单实例的高性能降低硬件成本和运维复杂度。 多核CPU环境：服务器配置了多核CPU，希望充分利用硬件资源。 新兴技术接受度高：愿意尝试新技术，能够承担早期采用者的风险。 整体未来发展趋势预估技术演进方向 Redis/Valkey：将继续优化单线程模型，增强集群管理和自动化运维能力。 DragonflyDB：将进一步完善多线程架构，提升内存效率和水平扩展能力。 市场格局预测 短期（1-2年）：Redis仍将保持市场主导地位，Valkey在开源社区快速增长，DragonflyDB在性能敏感场景获得采用。 中期（3-5年）：可能出现三足鼎立的局面，不同场景选择不同技术栈。 长期：架构创新（如DragonflyDB的多线程模型）可能成为主流，推动整个行业技术演进。 迁移策略建议Redis → Valkey 难度：极低，几乎无缝迁移。 步骤：备份数据 → 停止Redis服务 → 安装Valkey → 恢复数据 → 验证功能。 风险：几乎为零，Valkey承诺100%兼容Redis。 Redis → DragonflyDB 难度：中等，需要验证命令兼容性。 步骤：功能验证 → 性能测试 → 试点迁移 → 全量切换。 风险：某些高级特性可能不支持，需要代码调整。 混合部署策略在关键业务中，可以考虑混合部署策略： 核心业务使用Valkey确保稳定性和兼容性 高性能场景使用DragonflyDB处理热点数据 通过数据同步或分层架构实现无缝集成 十一、个人心得在2026年的技术格局中，Redis、Valkey和DragonflyDB各自代表了不同的技术哲学和发展路径： Redis：成熟的商业开源模式，功能丰富但许可复杂 Valkey：社区驱动的真正开源，兼容稳定但缺乏创新突破 DragonflyDB：架构创新的性能王者，前景广阔但生态待完善 选型决策框架： 先看许可要求：企业合规 &gt; 技术特性 再看性能需求：QPS/延迟指标 &gt; 架构偏好 最后看生态成熟度：运维成本 &gt; 学习曲线 技术选型没有绝对的对错，只有最适合当前业务场景的选择。建议在做出决策前，进行充分的概念验证（PoC）测试，结合具体的业务需求、团队技能和长期战略进行综合评估。随着技术的快速发展，保持架构的灵活性和可迁移性，比绑定单一技术栈更为重要。 ⚠️ 补充说明：因版本更新组建变化快，如有争议以官方文档为准。Redis Docs

一、StarRocks版本演进与核心特性1.1 版本历史与重大变革StarRocks自诞生以来经历了快速迭代，每个版本都带来了革命性的改进。让我们回顾一下关键版本的演进历程： StarRocks 3.0（2023年3月31日发布） - 里程碑式版本，首次引入存算分离架构，将数据持久化存储在远程对象存储或HDFS上，本地磁盘仅作为缓存使用，大幅提升了系统的弹性和扩展性。 StarRocks 3.1（2023年8月7日发布） - 重点增强共享数据集群能力，优化数据湖分析性能，改进存储引擎和数据导入机制，为大规模数据分析提供更强大的支撑。 StarRocks 3.2（2023年12月1日发布） - 在性能和易用性上再上新台阶，支持通过optimize table功能优化表结构，引入PIPE功能轻松从S3或HDFS导入大规模数据，并提供INSERT INTO FILES统一数据导出方案。 StarRocks 4.0（2026年1月16日最新版本） - 支持Operator和Drivers的并行准备，以及单节点批量fragment部署，进一步提升系统性能和资源利用率。 1.2 核心特性概览 极速查询性能：向量化执行引擎，MPP架构，智能查询优化 实时数据分析：支持毫秒级延迟的数据更新和查询 统一分析引擎：同时支持OLAP、实时分析、数据湖查询 MySQL协议兼容：无缝对接现有MySQL生态工具和应用 弹性扩展：从单机到大规模集群，平滑扩展 二、Debian 12环境下的StarRocks部署实践2.1 环境准备与系统要求硬件要求： 最低配置：4核CPU、16GB内存、100GB磁盘 生产环境：建议16核CPU、64GB内存、SSD磁盘 软件依赖： 123456789101112131415161718# 更新系统sudo apt update &amp;&amp; sudo apt upgrade -y# 安装基础依赖sudo apt install -y wget tar gzip curl net-tools vim# 安装MySQL客户端（用于连接StarRocks）sudo apt install -y mysql-client# 禁用交换分区（性能优化）sudo swapoff -asudo sed -i '/ swap / s/^\(.*\)$/#\1/g' /etc/fstab# 优化系统参数echo &quot;vm.swappiness=0&quot; | sudo tee -a /etc/sysctl.confecho &quot;vm.overcommit_memory=1&quot; | sudo tee -a /etc/sysctl.confecho &quot;fs.file-max=655350&quot; | sudo tee -a /etc/sysctl.confsudo sysctl -p 注意事项： 确保所有节点时间同步，建议配置NTP服务 关闭防火墙或开放相应端口（9030、9020、8040、8060等） 生产环境建议使用专用用户运行StarRocks，避免使用root用户 2.2 单机部署（快速入门）步骤1：下载StarRocks 123456789# 创建安装目录sudo mkdir -p /opt/starrockssudo chown -R $USER:$USER /opt/starrockscd /opt/starrocks# 下载最新版本（以4.0为例）wget https://download.starrocks.io/starrocks/StarRocks-4.0.0.tar.gztar -xzvf StarRocks-4.0.0.tar.gzmv StarRocks-4.0.0 starrocks 步骤2：配置FE（Frontend） 1234567891011121314cd starrocks# 创建数据目录mkdir -p fe/meta# 编辑FE配置文件cat &gt; fe/conf/fe.conf &lt;&lt; EOF# 基础配置priority_networks = 192.168.1.0/24 # 替换为实际IP网段http_port = 8030rpc_port = 9020query_port = 9030edit_log_port = 9010meta_dir = ${STARROCKS_HOME}/fe/metaEOF 步骤3：启动FE 12345# 获取初始密码（首次启动时生成）./fe/bin/start_fe.sh --daemon# 检查状态tail -f fe/log/fe.warn.log 步骤4：配置BE（Backend） 12345678910111213# 创建数据目录mkdir -p be/storage# 编辑BE配置文件cat &gt; be/conf/be.conf &lt;&lt; EOF# 基础配置priority_networks = 192.168.1.0/24 # 替换为实际IP网段heartbeat_service_port = 9050be_port = 9060brpc_port = 8060brpc_port = 8040storage_root_path = ${STARROCKS_HOME}/be/storageEOF 步骤5：启动BE并添加到集群 12345678# 启动BE./be/bin/start_be.sh --daemon# 使用MySQL客户端连接FEmysql -h 127.0.0.1 -P9030 -uroot# 在MySQL客户端中添加BE节点ALTER SYSTEM ADD BACKEND &quot;192.168.1.100:9050&quot;; # 替换为实际IP 2.3 Docker部署（开发测试首选）单容器部署： 1234567891011# 拉取最新镜像docker pull starrocks/allin1-ubuntu:latest# 运行容器docker run -d --name starrocks \ -p 9030:9030 \ -p 8030:8030 \ -p 9020:9020 \ -p 9060:9060 \ -v /path/to/data:/opt/starrocks \ starrocks/allin1-ubuntu:latest Docker Compose集群部署： 1234567891011121314151617181920212223242526272829303132333435363738version: '3.8'services: fe: image: starrocks/fe-ubuntu:latest container_name: starrocks-fe ports: - &quot;9030:9030&quot; - &quot;8030:8030&quot; - &quot;9020:9020&quot; volumes: - ./fe/conf:/opt/starrocks/fe/conf - ./fe/meta:/opt/starrocks/fe/meta environment: - FE_HOST=fe networks: - starrocks-net be1: image: starrocks/be-ubuntu:latest container_name: starrocks-be1 ports: - &quot;9060:9060&quot; - &quot;8040:8040&quot; - &quot;8060:8060&quot; volumes: - ./be1/conf:/opt/starrocks/be/conf - ./be1/storage:/opt/starrocks/be/storage environment: - FE_HOST=fe - BE_HOST=be1 depends_on: - fe networks: - starrocks-netnetworks: starrocks-net: driver: bridge 注意事项： Docker部署适合开发测试环境，生产环境建议使用物理机或虚拟机部署 数据持久化必须配置volume映射，避免容器重启数据丢失 网络配置要确保容器间可以互相访问 2.4 生产级集群部署集群规划： FE节点：3节点（1 Leader + 2 Follower），实现高可用 BE节点：根据数据量和查询负载动态扩展，建议至少3节点 硬件配置：FE节点注重CPU和内存，BE节点注重磁盘IO和内存 部署流程： 环境准备：所有节点执行相同的基础环境配置 FE集群部署：12345678# 第一个FE节点./fe/bin/start_fe.sh --daemon# 第二个FE节点./fe/bin/start_fe.sh --helper 192.168.1.101:9010 --daemon# 第三个FE节点./fe/bin/start_fe.sh --helper 192.168.1.101:9010 --daemon BE节点部署：123# 每个BE节点配置相同的fe_hostecho &quot;fe_host = 192.168.1.101:9020&quot; &gt;&gt; be/conf/be.conf./be/bin/start_be.sh --daemon 添加BE节点到集群：123ALTER SYSTEM ADD BACKEND &quot;192.168.1.102:9050&quot;;ALTER SYSTEM ADD BACKEND &quot;192.168.1.103:9050&quot;;ALTER SYSTEM ADD BACKEND &quot;192.168.1.104:9050&quot;; 监控与维护： 配置Prometheus + Grafana监控 定期检查集群健康状态 设置告警规则，及时发现异常 三、StarRocks核心语法与最佳实践3.1 数据模型选择明细模型（Duplicate Key）： 123456789101112131415CREATE TABLE user_events ( event_time DATETIME, user_id BIGINT, event_type VARCHAR(50), event_data VARCHAR(1000)) ENGINE=OLAPDUPLICATE KEY(event_time, user_id)PARTITION BY RANGE(event_time) ( PARTITION p202401 VALUES LESS THAN (&quot;2024-02-01&quot;), PARTITION p202402 VALUES LESS THAN (&quot;2024-03-01&quot;))DISTRIBUTED BY HASH(user_id) BUCKETS 10PROPERTIES ( &quot;replication_num&quot; = &quot;3&quot;); 聚合模型（Aggregate Key）： 123456789101112CREATE TABLE sales_data ( sale_date DATE, product_id BIGINT, store_id INT, sales_amount DECIMAL(20,2), sales_count BIGINT) ENGINE=OLAPAGGREGATE KEY(sale_date, product_id, store_id)DISTRIBUTED BY HASH(product_id) BUCKETS 10PROPERTIES ( &quot;replication_num&quot; = &quot;3&quot;); 主键模型（Primary Key）： 123456789101112CREATE TABLE user_profiles ( user_id BIGINT PRIMARY KEY, username VARCHAR(100), email VARCHAR(200), last_update_time DATETIME) ENGINE=OLAPPRIMARY KEY(user_id)DISTRIBUTED BY HASH(user_id) BUCKETS 10PROPERTIES ( &quot;replication_num&quot; = &quot;3&quot;, &quot;enable_persistent_index&quot; = &quot;true&quot; -- 3.2版本新特性，支持持久化索引); 3.2 高级查询优化物化视图： 123456789101112-- 创建物化视图加速聚合查询CREATE MATERIALIZED VIEW mv_sales_by_monthDISTRIBUTED BY HASH(sale_month) BUCKETS 10REFRESH ASYNC START('2024-01-01 00:00:00') EVERY(INTERVAL 1 HOUR)ASSELECT DATE_TRUNC('month', sale_date) AS sale_month, product_id, SUM(sales_amount) AS total_sales, COUNT(*) AS order_countFROM sales_dataGROUP BY sale_month, product_id; JSON数据处理： 123456789101112131415161718-- 创建支持JSON的表CREATE TABLE app_logs ( log_time DATETIME, user_id BIGINT, device_info JSON, event_data JSON) ENGINE=OLAPDUPLICATE KEY(log_time, user_id)DISTRIBUTED BY HASH(user_id) BUCKETS 10;-- 查询JSON字段SELECT log_time, user_id, device_info-&gt;'$.os' AS os_version, event_data-&gt;'$.event_type' AS event_typeFROM app_logsWHERE device_info-&gt;'$.os' = 'Android 12'; 注意事项： 分区字段选择：通常选择时间字段，控制单个分区数据量在10-100GB 分桶字段选择：选择高基数、经常用于JOIN或GROUP BY的字段 副本数设置：生产环境建议至少3副本，平衡性能和可用性 索引策略：合理使用前缀索引、Bloom Filter、Bitmap等索引类型 四、多语言客户端操作实战4.1 Python客户端示例安装依赖： 1pip install mysql-connector-python pandas sqlalchemy starrocks 完整操作示例： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127import mysql.connectorimport pandas as pdfrom sqlalchemy import create_enginefrom datetime import datetime, timedeltaclass StarRocksClient: def __init__(self, host='127.0.0.1', port=9030, user='root', password='', database='test'): self.config = { 'host': host, 'port': port, 'user': user, 'password': password, 'database': database, 'charset': 'utf8mb4' } self.connection = None def connect(self): &quot;&quot;&quot;建立连接&quot;&quot;&quot; try: self.connection = mysql.connector.connect(**self.config) print(&quot;✅ 成功连接到StarRocks&quot;) return True except Exception as e: print(f&quot;❌ 连接失败: {e}&quot;) return False def execute_query(self, sql): &quot;&quot;&quot;执行查询并返回结果&quot;&quot;&quot; if not self.connection: if not self.connect(): return None try: cursor = self.connection.cursor(dictionary=True) cursor.execute(sql) results = cursor.fetchall() cursor.close() return results except Exception as e: print(f&quot;❌ 查询执行失败: {e}&quot;) return None def insert_data(self, table_name, data_df): &quot;&quot;&quot;插入DataFrame数据&quot;&quot;&quot; if not self.connection: if not self.connect(): return False try: # 使用SQLAlchemy创建引擎 engine = create_engine(f'mysql+mysqlconnector://{self.config[&quot;user&quot;]}:@{self.config[&quot;host&quot;]}:{self.config[&quot;port&quot;]}/{self.config[&quot;database&quot;]}') # 写入数据 data_df.to_sql(table_name, engine, if_exists='append', index=False) print(f&quot;✅ 成功插入 {len(data_df)} 条数据到表 {table_name}&quot;) return True except Exception as e: print(f&quot;❌ 数据插入失败: {e}&quot;) return False def close(self): &quot;&quot;&quot;关闭连接&quot;&quot;&quot; if self.connection and self.connection.is_connected(): self.connection.close() print(&quot;🔌 连接已关闭&quot;)# 使用示例if __name__ == &quot;__main__&quot;: # 初始化客户端 client = StarRocksClient( host='192.168.1.100', port=9030, user='root', password='', database='test' ) # 连接数据库 if client.connect(): # 1. 创建测试表 create_table_sql = &quot;&quot;&quot; CREATE TABLE IF NOT EXISTS user_activity ( event_time DATETIME, user_id BIGINT, activity_type VARCHAR(50), duration_seconds INT ) ENGINE=OLAP DUPLICATE KEY(event_time, user_id) DISTRIBUTED BY HASH(user_id) BUCKETS 10 PROPERTIES (&quot;replication_num&quot; = &quot;1&quot;); &quot;&quot;&quot; client.execute_query(create_table_sql) # 2. 生成测试数据 data = { 'event_time': [datetime.now() - timedelta(minutes=i) for i in range(100)], 'user_id': [i % 10 for i in range(100)], 'activity_type': ['login', 'page_view', 'click', 'purchase'] * 25, 'duration_seconds': [i * 10 for i in range(100)] } df = pd.DataFrame(data) # 3. 插入数据 client.insert_data('user_activity', df) # 4. 查询数据 query_sql = &quot;&quot;&quot; SELECT DATE_TRUNC('hour', event_time) as hour, activity_type, COUNT(*) as event_count, AVG(duration_seconds) as avg_duration FROM user_activity GROUP BY hour, activity_type ORDER BY hour DESC, event_count DESC LIMIT 10; &quot;&quot;&quot; results = client.execute_query(query_sql) if results: print(&quot;📊 查询结果:&quot;) for row in results: print(row) # 5. 关闭连接 client.close() 4.2 Go语言客户端示例安装依赖： 1go get -u github.com/go-sql-driver/mysql 完整操作示例：  mainimport ( &quot;database/sql&quot; &quot;fmt&quot; &quot;log&quot; &quot;time&quot; _ &quot;github.com/go-sql-driver/mysql&quot;)type StarRocksClient struct { db *sql.DB}type UserActivity struct { EventTime time.Time UserID int64 ActivityType string Duration int}func NewStarRocksClient(host string, port int, user, password, database string) (*StarRocksClient, error) { dsn := fmt.Sprintf(&quot;%s:%s@tcp(%s:%d)/%s?charset=utf8mb4&amp;parseTime=True&amp;loc=Local&quot;, user, password, host, port, database) db, err := sql.Open(&quot;mysql&quot;, dsn) if err != nil { return nil, err } // 验证连接 if err := db.Ping(); err != nil { db.Close() return nil, err } return &amp;StarRocksClient{db: db}, nil}func (c *StarRocksClient) CreateTable() error { sql := ` CREATE TABLE IF NOT EXISTS go_user_activity ( event_time DATETIME, user_id BIGINT, activity_type VARCHAR(50), duration_seconds INT ) ENGINE=OLAP DUPLICATE KEY(event_time, user_id) DISTRIBUTED BY HASH(user_id) BUCKETS 10 PROPERTIES (&quot;replication_num&quot; = &quot;1&quot;); ` _, err := c.db.Exec(sql) return err}func (c *StarRocksClient) InsertData(activities []UserActivity) error { tx, err := c.db.Begin() if err != nil { return err } stmt, err := tx.Prepare(` INSERT INTO go_user_activity (event_time, user_id, activity_type, duration_seconds) VALUES (?, ?, ?, ?) `) if err != nil { tx.Rollback() return err } defer stmt.Close() for _, activity := range activities { _, err := stmt.Exec( activity.EventTime, activity.UserID, activity.ActivityType, activity.Duration, ) if err != nil { tx.Rollback() return err } } return tx.Commit()}func (c *StarRocksClient) QueryData() ([]map[string]interface{}, error) { rows, err := c.db.Query(` SELECT DATE_TRUNC('hour', event_time) as hour, activity_type, COUNT(*) as event_count, AVG(duration_seconds) as avg_duration FROM go_user_activity GROUP BY hour, activity_type ORDER BY hour DESC, event_count DESC LIMIT 10 `) if err != nil { return nil, err } defer rows.Close() // 获取列名 columns, err := rows.Columns() if err != nil { return nil, err } results := []map[string]interface{}{} for rows.Next() { // 创建值切片 values := make([]interface{}, len(columns)) valuePtrs := make([]interface{}, len(columns)) for i := range columns { valuePtrs[i] = &amp;values[i] } if err := rows.Scan(valuePtrs...); err != nil { return nil, err } // 创建结果映射 result := make(map[string]interface{}) for i, col := range columns { var v interface{} val := values[i] switch val := val.(type) { case []byte: v = string(val) case time.Time: v = val.Format(&quot;2006-01-02 15:04:05&quot;) default: v = val } result[col] = v } results = append(results, result) } return results, nil}func (c *StarRocksClient) Close() { if c.db != nil { c.db.Close() }}func main() { // 初始化客户端 client, err := NewStarRocksClient(&quot;192.168.1.100&quot;, 9030, &quot;root&quot;, &quot;&quot;, &quot;test&quot;) if err != nil { log.Fatalf(&quot;❌ 连接失败: %v&quot;, err) } defer client.Close() fmt.Println(&quot;✅ 成功连接到StarRocks&quot;) // 1. 创建表 if err := client.CreateTable(); err != nil { log.Fatalf(&quot;❌ 创建表失败: %v&quot;, err) } fmt.Println(&quot;✅ 表创建成功&quot;) // 2. 准备测试数据 now := time.Now() activities := []UserActivity{} for i := 0; i &lt; 100; i++ { activityTypes := []string{&quot;login&quot;, &quot;page_view&quot;, &quot;click&quot;, &quot;purchase&quot;} activities = append(activities, UserActivity{ EventTime: now.Add(time.Duration(-i) * time.Minute), UserID: int64(i % 10), ActivityType: activityTypes[i%4], Duration: i * 10, }) } // 3. 插入数据 if err := client.InsertData(activities); err != nil { log.Fatalf(&quot;❌ 数据插入失败: %v&quot;, err) } fmt.Printf(&quot;✅ 成功插入 %d 条数据
&quot;, len(activities)) // 4. 查询数据 results, err := client.QueryData() if err != nil { log.Fatalf(&quot;❌ 查询失败: %v&quot;, err) } fmt.Println(&quot;📊 查询结果:&quot;) for _, row := range results { fmt.Printf(&quot;时: %s, 类型: %s, 数量: %v, 平均时长: %v
&quot;, row[&quot;hour&quot;], row[&quot;activity_type&quot;], row[&quot;event_count&quot;], row[&quot;avg_duration&quot;]) }} 4.3 PHP客户端示例安装依赖： 12sudo apt install php-mysqlcomposer require doctrine/dbal 完整操作示例： &lt;?php/** * StarRocks PHP客户端示例 * 需要安装php-mysql扩展和composer依赖 */require_once __DIR__ . '/vendor/autoload.php';use Doctrine\DBAL\DriverManager;use Doctrine\DBAL\Exception;use DateTime;class StarRocksPHPClient { private $connection; private $config; public function __construct($host, $port, $user, $password, $database) { $this-&gt;config = [ 'host' =&gt; $host, 'port' =&gt; $port, 'user' =&gt; $user, 'password' =&gt; $password, 'database' =&gt; $database, ]; } public function connect() { try { $connectionParams = [ 'dbname' =&gt; $this-&gt;config['database'], 'user' =&gt; $this-&gt;config['user'], 'password' =&gt; $this-&gt;config['password'], 'host' =&gt; $this-&gt;config['host'], 'port' =&gt; $this-&gt;config['port'], 'driver' =&gt; 'pdo_mysql', 'charset' =&gt; 'utf8mb4', ]; $this-&gt;connection = DriverManager::getConnection($connectionParams); echo &quot;✅ 成功连接到StarRocks
