&quot;; return false; } } public function createTable() { $sql = &lt;&lt;&lt;SQLCREATE TABLE IF NOT EXISTS php_user_activity ( event_time DATETIME, user_id BIGINT, activity_type VARCHAR(50), duration_seconds INT) ENGINE=OLAPDUPLICATE KEY(event_time, user_id)DISTRIBUTED BY HASH(user_id) BUCKETS 10PROPERTIES (&quot;replication_num&quot; = &quot;1&quot;);SQL; try { $stmt = $this-&gt;connection-&gt;prepare($sql); $stmt-&gt;executeStatement(); echo &quot;✅ 表创建成功
