ge( prometheus.GaugeOpts{ Name: &quot;customer_service_active_sessions&quot;, Help: &quot;Number of active chat sessions&quot;, }, ), }}func (m *ServiceMetrics) Register() { prometheus.MustRegister(m.requestCount) prometheus.MustRegister(m.responseTime) prometheus.MustRegister(m.confidenceHist) prometheus.MustRegister(m.activeSessions)}func (m *ServiceMetrics) RecordRequest(endpoint, statusCode, category string) { m.requestCount.WithLabelValues(endpoint, statusCode, category).Inc()}func (m *ServiceMetrics) RecordResponseTime(endpoint, category string, duration float64) { m.responseTime.WithLabelValues(endpoint, category).Observe(duration)}func (m *ServiceMetrics) RecordConfidence(category string, confidence float32) { m.confidenceHist.WithLabelValues(category).Observe(float64(confidence))}func (m *ServiceMetrics) IncActiveSessions() { m.activeSessions.Inc()}func (m *ServiceMetrics) DecActiveSessions() { m.activeSessions.Dec()}// 新建客服服务func NewCustomerService(config *Config) (*CustomerService, error) { // 初始化Redis客户端（用于会话管理和缓存） redisClient := redis.NewClient(&amp;redis.Options{ Addr: config.RedisAddr, Password: config.RedisPassword, DB: 0, }) // 测试Redis连接 ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second) defer cancel() if _, err := redisClient.Ping(ctx).Result(); err != nil { log.Printf(&quot;警告: Redis连接失败: %v，将使用内存缓存&quot;, err) redisClient = nil } // 初始化监控指标 metrics := NewServiceMetrics() if config.MetricsEnabled { metrics.Register() } service := &amp;CustomerService{ config: config, redisClient: redisClient, metrics: metrics, } return service, nil}// 与Python后端通信func (s *CustomerService) callPythonBackend(ctx context.Context, request *ChatRequest) (*ChatResponse, error) { // 构建请求 jsonData, err := json.Marshal(request) if err != nil { return nil, fmt.Errorf(&quot;序列化请求失败: %w&quot;, err) } // 创建HTTP请求 req, err := http.NewRequestWithContext(ctx, &quot;POST&quot;, &quot;http://localhost:8000/api/v1/chat&quot;, bytes.NewBuffer(jsonData)) if err != 