ecordRequest(&quot;chat&quot;, &quot;200&quot;, req.Category) s.metrics.RecordResponseTime(&quot;chat&quot;, req.Category, duration) s.metrics.RecordConfidence(req.Category, response.Confidence) // 记录到Redis（如果可用） if s.redisClient != nil { go func() { ctx := context.Background() key := fmt.Sprintf(&quot;session:%s&quot;, req.SessionID) sessionData := map[string]interface{}{ &quot;last_query&quot;: req.UserQuery, &quot;last_response&quot;: response.Response, &quot;category&quot;: req.Category, &quot;confidence&quot;: response.Confidence, &quot;timestamp&quot;: time.Now().Unix(), } jsonData, _ := json.Marshal(sessionData) s.redisClient.Set(ctx, key, string(jsonData), 24*time.Hour) }() } // 返回响应 c.JSON(http.StatusOK, response)}// 健康检查func (s *CustomerService) HealthCheck(c *gin.Context) { status := map[string]interface{}{ &quot;status&quot;: &quot;healthy&quot;, &quot;service&quot;: &quot;customer-service-api&quot;, &quot;version&quot;: &quot;1.0.0&quot;, &quot;timestamp&quot;: time.Now().Format(time.RFC3339), &quot;uptime&quot;: time.Since(startTime).String(), &quot;model_path&quot;: s.config.ModelPath, &quot;redis_connected&quot;: s.redisClient != nil, } // 检查Python后端 pythonHealth := checkPythonBackend() status[&quot;python_backend&quot;] = pythonHealth c.JSON(http.StatusOK, status)}func checkPythonBackend() map[string]interface{} { ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second) defer cancel() resp, err := http.Get(&quot;http://localhost:8000/health&quot;) if err != nil { return map[string]interface{}{ &quot;status&quot;: &quot;unhealthy&quot;, &quot;error&quot;: err.Error(), } } defer resp.Body.Close() if resp.StatusCode != http.StatusOK { return map[string]interface{}{ &quot;status&quot;: &quot;unhealthy&quot;, &quot;code&quot;: resp.StatusCode, } } var healthData map[string]interface{} if err := json.NewDecoder(resp.Body).Decode(&amp;healthData); err != nil { return map[string]interface{}{ &quot;status&quot;: &quot;degraded&quot;, &quot;err